import React, { useState } from 'react';
import Footer from '../components/Footer';
import './Contact.css';

const methods = [
  { label: 'email',    val: 'aftab@example.com' },
  { label: 'location', val: 'Rawalpindi, Pakistan' },
  { label: 'github',   val: 'github.com/aftab-ahmad' },
  { label: 'linkedin', val: 'linkedin.com/in/aftab-ahmad' },
];

function Contact() {
  const [form, setForm] = useState({ name: '', email: '', message: '' });
  const [sent, setSent] = useState(false);

  const handle = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const submit = () => {
    if (!form.name || !form.email || !form.message) {
      alert('Please fill in all fields.');
      return;
    }
    setSent(true);
    setTimeout(() => {
      setSent(false);
      setForm({ name: '', email: '', message: '' });
    }, 3000);
  };

  return (
    <div className="page-enter">
      <div className="contact-wrap">

        <div className="contact-intro">
          <h2>Let's talk.</h2>
          <p>
            Whether it's a project, a job opportunity, or just a question — I'm happy
            to hear from you. I reply within a day usually.
          </p>
        </div>

        <div className="contact-methods">
          {methods.map(({ label, val }) => (
            <div key={label} className="contact-method">
              <div className="cm-label">{label}</div>
              <div className="cm-val">{val}</div>
            </div>
          ))}
        </div>

        <div className="form-box">
          <div className="field">
            <label>name</label>
            <input type="text" name="name" placeholder="Your name" value={form.name} onChange={handle} />
          </div>
          <div className="field">
            <label>email</label>
            <input type="email" name="email" placeholder="your@email.com" value={form.email} onChange={handle} />
          </div>
          <div className="field">
            <label>message</label>
            <textarea name="message" placeholder="What's on your mind?" value={form.message} onChange={handle} />
          </div>
          <button className={sent ? 'send-btn ok' : 'send-btn'} onClick={submit}>
            {sent ? 'Sent ✓' : 'Send message'}
          </button>
        </div>

      </div>
      <Footer />
    </div>
  );
}

export default Contact;
